var e=JSON.parse(`[{"id":"L3_1","type":"narration","speaker":null,"text":{"KOREA":"들리니, 발레리. 네가 만들던 곡이야.","JPN":"聞こえる？　ヴァレリー。あなたが作っていた曲よ。","ENG":"Do you hear that, Valeriy? It's the song you were writing.","TWN":"你有聽到嗎，瓦萊里？這是你寫的曲子。"},"stage":{"bg":"BLACK","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"narration","speaker":null,"text":{"KOREA":"후반부는 아직 정하지 못했지만.","JPN":"後半はまだ未完成だけど。","ENG":"Although the latter half hasn't been decided yet.","TWN":"不過後半段還沒有完成。"},"stage":{"bg":"BLACK","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"비켜, 불량품!!","JPN":"どけ、不良品！！","ENG":"Out of my way, defect!!","TWN":"讓開，瑕疵品！！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_HATE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L9_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"부전대장님, 근접전을 벌이시면 엄호하기 어렵습니다! 이탈하십시오!","JPN":"副戦隊長殿、近接戦になると援護が難しくなります！　離脱してください！","ENG":"Deputy Commander, I can't cover you when you're in melee combat! Please fall back!","TWN":"副戰隊長，你跟敵人太靠近的話，我不好掩護你！請保持距離！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L10_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"머리에 총 맞았니? 틈을 주면 중사를 쫓아갈 거야!","JPN":"頭でもぶつけちゃった？　隙を見せたら軍曹を追う機会を与えちゃうでしょ！","ENG":"Did you take a bullet to the head? If I back off, she's going after Sergeant!","TWN":"你腦袋有洞嗎？我不這樣的話，她就會趁隙去追中士！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"여기서 끝장을 낸다! 더 이상 빠져나가게 내버려 두지 않아!","JPN":"ここではっきり終わらせるの！　逃がすわけにはいかないわ！","ENG":"We end it here! I won't let anymore slip through our grasp!","TWN":"我要在這裡結束這一切！不能讓她再次溜走！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L13_1","type":"narration","speaker":null,"text":{"KOREA":"알고 있어. 네 취향과 많이 다르다는 거.","JPN":"わかってる。この曲があなたの好みじゃないってことは。","ENG":"I already know. It's not to your taste.","TWN":"我知道，這並不符合你的品味。"},"stage":{"bg":"BLACK","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"narration","speaker":null,"text":{"KOREA":"하지만 어쩔 수 없으려나. 곡에는 결국 연주하는 사람의 감정이 스며드니까.","JPN":"でも仕方ないかな。曲には演奏者の感情が入り込んでしまうから。","ENG":"But what else can I do? Music has its way of introducing the performer's emotions.","TWN":"但沒辦法，演奏者的私人情緒始終會滲入到曲子裡。"},"stage":{"bg":"BLACK","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"대체 뭐가 문제야? 뭐 때문에 이렇게 이 악물고 달려드는 거냐고!","JPN":"いったい何のために？　ここまで必死になって飛びかかってくるのはどうしてよ！","ENG":"What's wrong with you? Why are you so adamant on stopping me?!","TWN":"到底為什麼？為什麼要追著我不放！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"실험체들 때문에 그래? 어차피 멸망할 세상 때문에?!","JPN":"他の実験体のため？　世界のため？　どうせ滅亡するのに！？","ENG":"Is it because of the test subjects? Or the world that's going to end anyway?!","TWN":"是因為實驗體嗎？還是因為始終都會毀滅的世界？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L22_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"뻔한 질문이네. 대답해 줘 봤자 이해하지도 못할 거면서.","JPN":"くだらない質問ね。答えてあげても理解できないくせに。","ENG":"What stupid questions. Even if I answer them, you wouldn't understand.","TWN":"愚蠢的問題，就算我回答，你也沒辦法理解的。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_02"},{"id":"L23_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"우리 애들을 지켜 주기 위해서야.","JPN":"子どもたちを守るためよ。","ENG":"It's to protect my kids.","TWN":"是因為要保護我的孩子們。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"narration","speaker":null,"text":{"KOREA":"나는…. 류드밀라를, 너희들을 잃고 싶지 않았어.","JPN":"私は……リュドミラを、あなたたちを失いたくなかった。","ENG":"I didn't want... to lose Lyudmila. I didn't want to lose you all.","TWN":"我…不想失去盧德米拉，還有你們。"},"stage":{"bg":"BLACK","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"narration","speaker":null,"text":{"KOREA":"단 한 사람도.","JPN":"誰一人も。","ENG":"Not even a single soul.","TWN":"一個人也不想失去。"},"stage":{"bg":"BLACK","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"너희들은 어차피 틀에 찍혀 나온 소모품이잖아?","JPN":"あなたたちはどうせ型から作られた消耗品でしょう？","ENG":"But you're all expendables produced in molds!","TWN":"你們也只不過是量產的消耗品而已！"},"stage":{"bg":"BLACK","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"소꿉놀이에 너무 심취했나 보네. 너나 나나","JPN":"ままごとに夢中になりすぎたのね。あなたも、私も。","ENG":"Guess you and I have been too caught up in our little playtime.","TWN":"看來我們都太沉迷在扮家家酒的遊戲裡了。"},"stage":{"bg":"BLACK","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"그래. 그리고 넌 오늘 그 소모품에게 죽는 거야.","JPN":"そう。そしてあなたは今日、その消耗品に殺されることになる。","ENG":"Yeah. And you're gonna die to an expendable today.","TWN":"沒錯，而且你今天就會死在消耗品手裡。"},"stage":{"bg":"BLACK","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L34_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"후훗, 자신만만하네.","JPN":"ふふっ、自信満々ね。","ENG":"Fu fuu, how confident you sound.","TWN":"哼，不自量力。"},"stage":{"bg":"BLACK","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L35_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"그럼 어디…. 마지막으로 변주를 줘 볼까?","JPN":"それじゃ……最後に変奏してみようかしら。","ENG":"Then... shall I perform a variation for the last time?","TWN":"那麼……我就讓你見識一下，最後一次變奏吧？"},"stage":{"bg":"BLACK","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L38_1","type":"narration","speaker":null,"text":{"KOREA":"우습지? 반드시 저 녀석들을….","JPN":"笑えるでしょ？　必ずあいつらを……","ENG":"Funny, right? I really wanted to...","TWN":"是不是很可笑？我本想把她們……"},"stage":{"bg":"BLACK","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"narration","speaker":null,"text":{"KOREA":"엘리시움 필하모닉을, 이 세상에서 지워 버리고 싶었는데.","JPN":"エリシウムフィルハーモニーを、この世界から消したかったのに。","ENG":"erase those Elysium Philharmonic scum from the face of this earth.","TWN":"把愛樂組織，從這個世上徹底消滅掉。"},"stage":{"bg":"BLACK","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"narration","speaker":null,"text":{"KOREA":"그렇게 해서, 불량품이 아니고 싶었는데.","JPN":"そうやって、不良品じゃなくなりたかったのに。","ENG":"To be able to say that we're not defects.","TWN":"我本想以此證明自己不是瑕疵品。"},"stage":{"bg":"BLACK","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"너희들의 그 잘난 소꿉놀이를…. 비극으로 끝내 줄게!","JPN":"あなたたちのそのままごとを……悲劇で終わらせてあげるわ！","ENG":"No more playing house. This ends... with a tragedy!","TWN":"我要讓你們幼稚的遊戲…以悲劇結尾！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_HYPER_ATTACK_START"},{"id":"L45_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"이런, 이쪽으로!?","JPN":"なにっ、こっちだと！？","ENG":"What? She's headed this way?!","TWN":"糟糕，往這邊？！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"예고르……? 안 돼!","JPN":"イェゴール……？　ダメ！","ENG":"Yegor...? NO!","TWN":"伊高爾……？不可以！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L47_1","type":"narration","speaker":null,"text":{"KOREA":"이런 말은 낯뜨겁지만, 내 <color=#ffd34c>장난감</color>처럼.","JPN":"こんな話は恥ずかしいけど、私の<color=#ffd34c>オモチャ</color>みたいに。","ENG":"Although it's embarrassing to say this, but, it's just like my <color=#ffd34c>toy</color>.","TWN":"說這些話雖然有些難為情，但就像我的<color=#ffd34c>玩具</color>一樣，"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"narration","speaker":null,"text":{"KOREA":"쓸모없어서 버려지는 물건이라도, 사람의 손을 타면 달라질 수 있으니까.","JPN":"役に立たなくなって捨てられる物でも、人の手で生まれ変わったりするじゃない。","ENG":"Even if it was thrown out because it was useless, it could still change after some care.","TWN":"即便是毫無用處的廢物，經過人的雙手也可能變得有些用處。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"narration","speaker":null,"text":{"KOREA":"마음에 안 들지만…. 피가 묻을수록 바뀌는 것 없이 녹만 슬더라.","JPN":"気に入らないけど……血ってものは付けば付くほど、変わるどころか錆びつくだけなんだよね。","ENG":"It's unsatisfying, but... it didn't change and only rusted as it got covered in more blood.","TWN":"雖然很不甘心…沾上越來越多的鮮血，得到的卻只是身體生銹，其他沒有任何改變。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"narration","speaker":null,"text":{"KOREA":"그러니까, 어차피 볼 피라면 내가 보는 편이 나아.","JPN":"だから、血を流すことになるなら自分の血を流した方がマシ。","ENG":"So, if something has to be drenched in blood, it might as well be me.","TWN":"所以，如果悲劇終將到來，還是由我來親自面對。"},"stage":{"bg":"BLACK","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"헉…… 헉…….","JPN":"はあ……はあ……","ENG":"*Huff... Huff...*","TWN":"呼……呼……"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L7_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"이 진동은…… 지상에서 뭔가 문제가 생긴 건가?","JPN":"この揺れ……地上で何か問題が起きたのか？","ENG":"This rumbling... Did something happen above?","TWN":"剛剛的震動……是地面發生什麼問題嗎？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"부전대장님? 어디 계십니까, 부전대장님!","JPN":"副戦隊長殿？　どこですか、副戦隊長殿！","ENG":"Deputy Commander? Deputy Commander! Where are you?!","TWN":"副戰隊長？副戰隊長，你在哪裡！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"……여기야, 예고르.","JPN":"……ここよ、イェゴール。","ENG":"...I'm here, Yegor.","TWN":"……我在這裡，伊高爾。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"부, 부전대장님……. 몸이…….","JPN":"ふ、副戦隊長殿……お身体が……","ENG":"D-Deputy Commander... you're wounded...","TWN":"副…副戰隊長……你的身體……"},"stage":{"bg":"HARMONY2_05","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"그러게. 팔도 다리도, 장난감이랑 같이 날아가 버렸어.","JPN":"そうね。手も足も、オモチャと一緒にふっ飛んじゃった。","ENG":"Yeah. My arms and legs, they are gone... alongside the toy.","TWN":"沒錯，我的手和腳都和玩具一起飛走了。"},"stage":{"bg":"HARMONY2_05","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"출력이 너무 높았으려나. 급한 마음에 리미터를 그만 부숴 버렸거든.","JPN":"出力が高すぎたかな。焦っててついリミッターを壊しちゃったの。","ENG":"I guess my output was too high. I was in such a hurry that I broke my limiter.","TWN":"可能是輸出太高，我一時心急，不小心弄壞限制器。"},"stage":{"bg":"HARMONY2_05","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HARMONY2_05","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"셰나는?","JPN":"シェナは？","ENG":"What about Shena?","TWN":"世娜呢？"},"stage":{"bg":"HARMONY2_05","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"반응이 잡히지 않습니다. 바이올린도 보이지 않아요.","JPN":"反応がありません。バイオリンも見当たらないです。","ENG":"I don't detect any signal of her. Nor her violin.","TWN":"沒發現任何反應，也沒看見小提琴。"},"stage":{"bg":"HARMONY2_05","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"……그래. 다행이네. 이 상태로는 싸우기 힘들 것 같거든.","JPN":"……そう。よかった。この状態で戦うのは無理だから。","ENG":"...Okay. That's good news. I don't think I can fight her in this state.","TWN":"……是嗎，那就好。我現在這樣也很難再打下去。"},"stage":{"bg":"HARMONY2_05","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"조금만 참으십시오. 지금 수송기에 호송 요청을 보내겠습니다.","JPN":"少しだけご辛抱ください。今輸送船に搬送を要請します。","ENG":"Please hold on. I'll request a transport convoy.","TWN":"撐住，我立刻向運輸機請求護送。"},"stage":{"bg":"HARMONY2_05","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"젠장, 전파 방해인가? 왜 응답이…….","JPN":"くそ、電波妨害か？　どうして応答が……","ENG":"Dammit! Radio jamming? Why won't they respond...?","TWN":"該死，是電波干擾？為什麼沒人回答……"},"stage":{"bg":"HARMONY2_05","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"그러지 마. 참을 만해.","JPN":"いいよ。このくらいなら我慢できる。","ENG":"Stop. I can bear it.","TWN":"你不要這樣，我還能忍。"},"stage":{"bg":"HARMONY2_05","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"부전대장님!","JPN":"副戦隊長殿！","ENG":"Deputy Commander!","TWN":"副戰隊長！"},"stage":{"bg":"HARMONY2_05","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L31_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"다들 한창 바쁠 때잖니. 동요하는 사람이 없어야 돼.","JPN":"みんな今忙しいじゃない。動揺させちゃいけないわ。","ENG":"It's hectic for everyone at the moment. We can't have anyone upset right now.","TWN":"現在情況危急，不能讓大家動搖。"},"stage":{"bg":"HARMONY2_05","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"그래. 이를테면 우리 귀여운 중사님이라거나.","JPN":"そう。例えば、かわいい軍曹とかね。","ENG":"Yeah. For instance, our cute and precious sergeant.","TWN":"沒錯，譬如我們可愛的中士。"},"stage":{"bg":"HARMONY2_05","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"하, 하지만…. 이대로 있으면 재생 시술도 어려울 수 있습니다.","JPN":"で、ですが……このままだと、再生の施術も難しくなる可能性があります。","ENG":"B-but... Leaving you like this will make the regeneration procedure even more difficult.","TWN":"可…可是…再拖下去，我怕連重建都沒辦法。"},"stage":{"bg":"HARMONY2_05","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"아시지 않습니까. 저희는 어차피 원본의…….","JPN":"ご存じではありませんか。自分たちはどうせオリジナルの……","ENG":"You already know. That we're all just clones of–","TWN":"畢竟你也知道，我們不過是本體的……"},"stage":{"bg":"HARMONY2_05","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"쉿.","JPN":"しっ。","ENG":"Shush.","TWN":"噓。"},"stage":{"bg":"HARMONY2_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L37_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"중사님에게 하고 싶은 얘기가 있어. 잘 듣고 가서 전해 줘.","JPN":"軍曹に話したいことがあるの。よく聞いて、ちゃんと伝えて。","ENG":"There's something I want to tell our sergeant. Please listen carefully and deliver her this message.","TWN":"我有話對中士說，你記好，替我轉告她。"},"stage":{"bg":"HARMONY2_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};